/**
 * @fileoverview Toast helpers — pure utility functions.
 * @module module/Toast/helpers
 */

import { ICONS } from './constants.js';

/**
 * Get the icon SVG markup for a toast type.
 *
 * @param {string} type — success | error | warning | info
 * @returns {string} SVG markup
 */
export function getTypeIcon(type) {
    return ICONS[type] || ICONS.info;
}

/**
 * Resolve position CSS classes for a toast container.
 *
 * @param {string} position — e.g. 'top-right', 'bottom-center'
 * @returns {{ x: string, y: string, align: string }}
 */
export function resolvePositionStyles(position) {
    const [y, x] = position.split('-');
    const styles = {};

    styles.y = y === 'top' ? 'top' : 'bottom';
    styles.yValue = 'var(--ts-offset)';

    if (x === 'left') {
        styles.x = 'left';
        styles.xValue = 'var(--ts-offset)';
        styles.align = 'flex-start';
    } else if (x === 'center') {
        styles.x = 'left';
        styles.xValue = '50%';
        styles.transform = 'translateX(-50%)';
        styles.align = 'center';
    } else {
        styles.x = 'right';
        styles.xValue = 'var(--ts-offset)';
        styles.align = 'flex-end';
    }

    return styles;
}

/**
 * Generate a unique toast ID.
 * @param {number} counter — current counter value
 * @returns {string}
 */
export function toastId(counter) {
    return `toast-${counter}`;
}
