/**
 * @fileoverview Toast constants — CSS classes, ARIA attributes, selectors, defaults.
 * @module module/Toast/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    CONTAINER:  'toast-container',
    TOAST:      'toast',
    ICON:       'toast-icon',
    BODY:       'toast-body',
    TITLE:      'toast-title',
    MESSAGE:    'toast-message',
    CLOSE:      'toast-close',
    PROGRESS:   'toast-progress',
    ENTERING:   'is-entering',
    EXITING:    'is-exiting',
    VISIBLE:    'is-visible',
});

/** ARIA role values */
export const ARIA = Object.freeze({
    ALERT: 'alert',
    STATUS: 'status',
    LIVE_POLITE: 'polite',
    LIVE_ASSERTIVE: 'assertive',
});

/** DOM selectors */
export const SEL = Object.freeze({
    CONTAINER: '.toast-container',
    TOAST:     '.toast',
    CLOSE:     '.toast-close',
    PROGRESS:  '.toast-progress',
});

/** Toast type icons (inline SVG paths) */
export const ICONS = Object.freeze({
    success: '<svg width="20" height="20" viewBox="0 0 20 20" fill="none"><circle cx="10" cy="10" r="10" fill="currentColor" opacity=".15"/><path d="M6 10l3 3 5-6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>',
    error:   '<svg width="20" height="20" viewBox="0 0 20 20" fill="none"><circle cx="10" cy="10" r="10" fill="currentColor" opacity=".15"/><path d="M7 7l6 6M13 7l-6 6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>',
    warning: '<svg width="20" height="20" viewBox="0 0 20 20" fill="none"><circle cx="10" cy="10" r="10" fill="currentColor" opacity=".15"/><path d="M10 6v5M10 13.5v.5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>',
    info:    '<svg width="20" height="20" viewBox="0 0 20 20" fill="none"><circle cx="10" cy="10" r="10" fill="currentColor" opacity=".15"/><path d="M10 9v5M10 6.5v.5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    type: 'info',
    title: null,
    message: '',
    duration: 4000,
    position: 'top-right',
    closable: true,
    showProgress: true,
    pauseOnHover: true,
});

/** Valid positions */
export const POSITIONS = Object.freeze([
    'top-right', 'top-left', 'top-center',
    'bottom-right', 'bottom-left', 'bottom-center',
]);

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('Toast', {
    CONTAINER   : { class: 'toast-container', aliases: ['container', 'stack'] },
    TOAST       : { class: 'toast-item', aliases: ['toast', 'item', 'notification'] },
    ICON        : { class: 'toast-icon', aliases: ['icon'], tag: 'span' },
    BODY        : { class: 'toast-body', aliases: ['body', 'content'] },
    TITLE       : { class: 'toast-title', aliases: ['title', 'heading'] },
    MESSAGE     : { class: 'toast-message', aliases: ['message', 'text'] },
    CLOSE       : { class: 'toast-close', aliases: ['close', 'dismiss'], tag: 'button' },
    PROGRESS    : { class: 'toast-progress', aliases: ['progress', 'bar', 'timer'] },
});

PART.CONTAINER.jit = 'fixed z-[9999] flex flex-col gap-[var(--ts-gap)] pointer-events-none [font-family:var(--ts-font-stack)] [--ts-offset:16px] [--ts-gap:0.75rem] [--ts-font-stack:inherit]';
PART.TOAST.jit    = 'relative flex items-start gap-[var(--ts-inner-gap)] p-[var(--ts-padding)] rounded-[var(--ts-radius)] bg-[var(--ts-bg)] fg-[var(--ts-text)] shadow-[var(--ts-shadow)] pointer-events-auto min-w-[var(--ts-min-w)] max-w-[var(--ts-max-w)] [border:1px_solid_var(--ts-border)] ' + TRANSITION_COLORS + ' {is-entering}:opacity-0 {is-entering}:[transform:translateY(-12px)_scale(0.96)] {is-visible}:opacity-100 {is-visible}:[transform:translateY(0)_scale(1)] {is-visible}:[transition:opacity_.25s_ease,transform_.25s_ease] {is-exiting}:opacity-0 {is-exiting}:[transform:translateX(100%)_scale(0.96)] {is-exiting}:[transition:opacity_.2s_ease,transform_.2s_ease] [&[data-type=success]]:[border-left:3px_solid_var(--ts-success)] [&[data-type=error]]:[border-left:3px_solid_var(--ts-error)] [&[data-type=warning]]:[border-left:3px_solid_var(--ts-warning)] [&[data-type=info]]:[border-left:3px_solid_var(--ts-info)] [&[data-type=success]_.toast-progress]:[background:var(--ts-success)] [&[data-type=error]_.toast-progress]:[background:var(--ts-error)] [&[data-type=warning]_.toast-progress]:[background:var(--ts-warning)] [&[data-type=info]_.toast-progress]:[background:var(--ts-info)]';
PART.ICON.jit     = 'flex items-center justify-center shrink-0 w-[20px] h-[20px] mt-[1px] {toast-type-success}:fg-[var(--ts-success)] {toast-type-error}:fg-[var(--ts-error)] {toast-type-warning}:fg-[var(--ts-warning)] {toast-type-info}:fg-[var(--ts-info)]';
PART.BODY.jit     = 'flex-1 min-w-0';
PART.TITLE.jit    = 'text-[var(--ts-title-size)] font-semibold fg-[var(--ts-title-color)] mb-[2px]';
PART.MESSAGE.jit  = 'text-[var(--ts-font-size)] fg-[var(--ts-text)] leading-[1.4]';
PART.CLOSE.jit    = 'flex items-center justify-center shrink-0 w-[24px] h-[24px] p-0 [border:none] bg-transparent cursor-pointer fg-[var(--ts-close-color)] rounded-[4px] [transition:background_.15s] hover:bg-[var(--ts-close-hover-bg)]';
PART.PROGRESS.jit = 'absolute bottom-0 left-0 h-[3px] rounded-b-[var(--ts-radius)] [transition:width_linear]';