/**
 * @fileoverview Toast component — modular entry point.
 *
 * Manages a global toast queue with per-position stacking, auto-dismiss
 * with progress bar, pause-on-hover, and enter/exit animations.
 *
 * @module module/Toast
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS, CLS } from './constants.js';
import { toastId } from './helpers.js';
import { TOAST_TRANSITIONS } from './state.js';
import { getContainer, createToastEl, removeToastEl } from './view.js';
import { bindToastEvents } from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

/** Active toast instances keyed by ID */
const activeToasts = new Map();

/** Global counter for unique IDs */
let counter = 0;

/**
 * Toast — stackable notification component.
 *
 * Usage:
 *   razyui.Toast.show({ type: 'success', message: 'Saved!' });
 *   razyui.Toast.show({ type: 'error', title: 'Oops', message: 'Something failed', duration: 6000 });
 *
 * @param {object} config
 * @param {string}   [config.type='info']        — success | error | warning | info
 * @param {string}   [config.title]              — optional title
 * @param {string}   [config.message='']         — message text
 * @param {number}   [config.duration=4000]      — auto-dismiss ms (0 = manual only)
 * @param {string}   [config.position='top-right'] — placement
 * @param {boolean}  [config.closable=true]      — show close button
 * @param {boolean}  [config.showProgress=true]  — show countdown bar
 * @param {boolean}  [config.pauseOnHover=true]  — pause timer on hover
 * @param {Function} [config.onClose]            — callback when dismissed
 */
const Toast = class {
    #id        = null;
    #destroyed = false;
    #el        = null;
    #config    = {};
    #timer     = null;
    #startTime = 0;
    #remaining = 0;
    #progressEl = null;
    #progressRAF = null;
    #eventAC   = null;
    #fallbackTimer = null;
    #state     = 'idle';

    constructor(config = {}) {
        this.#config    = { ...DEFAULTS, ...config };
        this.#id        = toastId(++counter);
        this.#remaining = this.#config.duration;

        this.#show();
    }

    #show() {
        const config = this.#config;
        const container = getContainer(config.position);

        // Build DOM
        const el = createToastEl({
            id: this.#id,
            type: config.type,
            title: config.title,
            message: config.message,
            closable: config.closable,
            showProgress: config.showProgress,
        });

        this.#el = el;
        this.#progressEl = el.querySelector('.toast-progress');

        // Bind events
        this.#eventAC = bindToastEvents(el, {
            dismiss: () => this.dismiss(),
            pause:   () => this.#pause(),
            resume:  () => this.#resume(),
        }, config);

        // Insert into container
        const isBottom = config.position.startsWith('bottom');
        if (isBottom) {
            container.appendChild(el);
        } else {
            container.insertBefore(el, container.firstChild);
        }

        activeToasts.set(this.#id, this);
        this.#state = 'entering';

        // Trigger enter animation
        requestAnimationFrame(() => {
            requestAnimationFrame(() => {
                el.classList.remove(CLS.ENTERING);
                el.classList.add(CLS.VISIBLE);
                this.#state = 'visible';

                // Start auto-dismiss timer
                if (config.duration > 0) {
                    this.#startTimer();
                }
            });
        });
    }

    #startTimer() {
        this.#startTime = Date.now();

        if (this.#config.showProgress && this.#progressEl) {
            this.#animateProgress();
        }

        this.#timer = setTimeout(() => {
            this.dismiss();
        }, this.#remaining);
    }

    #animateProgress() {
        const total    = this.#config.duration;
        const progressEl = this.#progressEl;

        progressEl.style.width = '100%';

        const tick = () => {
            if (this.#state === 'exiting' || this.#state === 'removed') return;

            const elapsed = Date.now() - this.#startTime;
            const spent   = total - this.#remaining + elapsed;
            const pct     = Math.max(0, 100 - (spent / total) * 100);

            progressEl.style.width = pct + '%';

            if (pct > 0 && this.#state !== 'paused') {
                this.#progressRAF = requestAnimationFrame(tick);
            }
        };

        this.#progressRAF = requestAnimationFrame(tick);
    }

    #pause() {
        if (this.#state !== 'visible') return;
        this.#state = 'paused';

        clearTimeout(this.#timer);
        this.#timer = null;

        if (this.#progressRAF) {
            cancelAnimationFrame(this.#progressRAF);
            this.#progressRAF = null;
        }

        const elapsed = Date.now() - this.#startTime;
        this.#remaining = Math.max(0, this.#remaining - elapsed);
    }

    #resume() {
        if (this.#state !== 'paused') return;
        this.#state = 'visible';

        if (this.#remaining > 0) {
            this.#startTimer();
        }
    }

    /** Dismiss this toast with exit animation. */
    dismiss() {
        if (this.#state === 'exiting' || this.#state === 'removed') return;
        this.#state = 'exiting';

        clearTimeout(this.#timer);
        this.#timer = null;

        if (this.#progressRAF) {
            cancelAnimationFrame(this.#progressRAF);
            this.#progressRAF = null;
        }

        const el = this.#el;
        el.classList.remove(CLS.VISIBLE);
        el.classList.add(CLS.EXITING);

        const onEnd = () => {
            el.removeEventListener('animationend', onEnd);
            el.removeEventListener('transitionend', onEnd);
            this.#cleanup();
        };

        el.addEventListener('animationend', onEnd);
        el.addEventListener('transitionend', onEnd);

        // Fallback timeout in case animation doesn't fire
        this.#fallbackTimer = setTimeout(() => {
            if (this.#state !== 'removed') this.#cleanup();
        }, 400);
    }

    #cleanup() {
        if (this.#state === 'removed') return;
        this.#state = 'removed';

        if (this.#fallbackTimer) {
            clearTimeout(this.#fallbackTimer);
            this.#fallbackTimer = null;
        }

        this.#eventAC?.abort();

        removeToastEl(this.#el);
        activeToasts.delete(this.#id);

        emitEvent(this.#el, 'close');
        if (typeof this.#config.onClose === 'function') {
            this.#config.onClose();
        }
    }

    /** Get the toast ID. */
    get id() { return this.#id; }

    /** Get current state. */
    get state() { return this.#state; }

    /** Alias for dismiss() — standard destroy API. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.dismiss();
    }

    /** Get control object for external manipulation. */
    getControl() {
        const self = this;
        return {
            dismiss: () => self.dismiss(),
            destroy: () => self.destroy(),
            get id()    { return self.id; },
            get state() { return self.state; },
            get element() { return self.#el; },
            get destroyed() { return self.#destroyed; },
        };
    }

    // ═══════════════════════════════════════
    //  Static API
    // ═══════════════════════════════════════

    /**
     * Show a new toast notification.
     * @param {object} config — toast configuration
     * @returns {Toast}
     */
    static show(config) {
        return new Toast(config);
    }

    /** Shorthand: success toast */
    static success(message, opts = {}) {
        return Toast.show({ ...opts, type: 'success', message });
    }

    /** Shorthand: error toast */
    static error(message, opts = {}) {
        return Toast.show({ ...opts, type: 'error', message });
    }

    /** Shorthand: warning toast */
    static warning(message, opts = {}) {
        return Toast.show({ ...opts, type: 'warning', message });
    }

    /** Shorthand: info toast */
    static info(message, opts = {}) {
        return Toast.show({ ...opts, type: 'info', message });
    }

    /** Dismiss all active toasts. */
    static dismissAll() {
        for (const toast of activeToasts.values()) {
            toast.dismiss();
        }
    }

    /** Get count of active toasts. */
    static get count() {
        return activeToasts.size;
    }
};

export default Toast;
