/**
 * @fileoverview Toast view — DOM creation / teardown for toast items and container.
 * @module module/Toast/view
 */

import { CLS, PART } from './constants.js';
import { getTypeIcon, resolvePositionStyles } from './helpers.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

// Container cache: position → DOM element
const containers = new Map();

/**
 * Get or create a positioned toast container.
 *
 * @param {string} position — e.g. 'top-right'
 * @returns {HTMLElement}
 */
export function getContainer(position) {
    if (containers.has(position)) return containers.get(position);

    const $container = PART.CONTAINER.create({ 'data-position': position });
    const el = $container[0];

    // Position styles
    const pos = resolvePositionStyles(position);
    el.style[pos.y] = pos.yValue;
    el.style[pos.x] = pos.xValue;
    if (pos.transform) el.style.transform = pos.transform;
    el.style.alignItems = pos.align;

    document.body.appendChild(el);
    zIndexRegistry.acquire(el);
    containers.set(position, el);
    return el;
}

/**
 * Build a single toast DOM element.
 *
 * @param {object} config — { id, type, title, message, closable, showProgress, onClose }
 * @returns {HTMLElement} the toast element
 */
export function createToastEl(config) {
    const { id, type, title, message, closable, showProgress } = config;

    const $toast = PART.TOAST.create({
        id,
        role: type === 'error' ? 'alert' : 'status',
        'aria-live': type === 'error' ? 'assertive' : 'polite',
        'data-type': type,
    });
    $toast.addClass(CLS.TOAST).addClass(CLS.ENTERING);
    const toast = $toast[0];

    // Icon
    const $icon = PART.ICON.create();
    $icon.addClass(`toast-type-${type}`);
    $icon[0].innerHTML = getTypeIcon(type);
    $toast.append($icon);

    // Body
    const $body = PART.BODY.create();

    if (title) {
        const $title = PART.TITLE.create();
        $title.text(title);
        $body.append($title);
    }

    const $msg = PART.MESSAGE.create();
    $msg.text(message);
    $body.append($msg);
    $toast.append($body);

    // Close button
    if (closable) {
        const $close = PART.CLOSE.create({
            type: 'button',
            'aria-label': 'Close',
        });
        $close[0].innerHTML = '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M3 3l8 8M11 3l-8 8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>';
        $toast.append($close);
    }

    // Progress bar
    if (showProgress) {
        const $progress = PART.PROGRESS.create();
        $toast.append($progress);
    }

    return toast;
}

/**
 * Remove a toast element from the DOM.
 *
 * @param {HTMLElement} el — the toast element
 */
export function removeToastEl(el) {
    const container = el.parentElement;
    el.remove();

    // Clean up empty containers
    if (container && container.children.length === 0) {
        const position = container.dataset.position;
        zIndexRegistry.release(container);
        container.remove();
        containers.delete(position);
    }
}
